import{_ as a,o as t,c as o,al as r}from"./chunks/framework.DtH0F2t4.js";const g=JSON.parse('{"title":"Technology","description":"","frontmatter":{"layout":"page"},"headers":[],"relativePath":"technology.md","filePath":"technology.md"}'),n={name:"technology.md"};function s(i,e,l,h,c,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="technology" tabindex="-1">Technology <a class="header-anchor" href="#technology" aria-label="Permalink to &quot;Technology&quot;">​</a></h1><p>eodash is the core framework, state manager and component communicator between both core and third-party widgets. It is based on <a href="https://vuejs.org/" target="_blank" rel="noreferrer">vue.js</a> (version 3).</p><p>The core widgets are built using <a href="https://eox-a.github.io/EOxElements/" target="_blank" rel="noreferrer">EOxElements</a> and are extended through how they interact with each other.</p><p>The state management within eodash is based on <a href="https://stacspec.org" target="_blank" rel="noreferrer">SpatioTemporal Asset Catalogs (STAC)</a>. Each component can register to a central store, provided by <a href="https://pinia.vuejs.org/" target="_blank" rel="noreferrer">pinia</a>.</p><p>eodash can be used either as a <a href="https://www.webcomponents.org/introduction" target="_blank" rel="noreferrer">web component</a> or as a package that can be build based on <a href="https://vitejs.dev/" target="_blank" rel="noreferrer">vite</a>.</p><h1 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h1><ul><li><a href="https://eodash.github.io/eodash" target="_blank" rel="noreferrer">eodash</a><ul><li>library for eodash client instance creation and web component release</li><li>extendable and configurable through widgets</li></ul></li><li><a href="https://github.com/eodash/eodash_catalog" target="_blank" rel="noreferrer">eodash_catalog</a><ul><li>library for creation of STAC catalog supported by eodash</li><li>supports multiple backends and services</li></ul></li><li><a href="https://github.com/eodash/eodash-pages-template" target="_blank" rel="noreferrer">eodash-pages-template</a><ul><li>template repo showing how to instantiate eodash as part of a vitepress application</li></ul></li><li><a href="https://github.com/eodash/eodash-instance-template" target="_blank" rel="noreferrer">eodash-instance-template</a><ul><li>template repo showing how to integrate eodash as package for building and extension of functionality into a vite based application</li></ul></li><li><a href="https://github.com/eodash/catalog-template" target="_blank" rel="noreferrer">catalog-template</a><ul><li>template repo with example setup for a catalog configuration and deployment as github pages</li></ul></li><li><a href="https://github.com/eodash/eodash-docs" target="_blank" rel="noreferrer">eodash-docs</a><ul><li>central location for eodash ecosystem documentation</li></ul></li><li><a href="https://github.com/eodash/eodash-schemas" target="_blank" rel="noreferrer">eodash-schemas</a><ul><li>JSON schemas for eodash catalog configs for purposes of validation - matching <a href="https://github.com/eodash/eodash_catalog/wiki" target="_blank" rel="noreferrer">eodash catalog wiki entries</a></li></ul></li><li><a href="https://github.com/eodash/eodash-extension" target="_blank" rel="noreferrer">eodash STAC Extension</a></li><li><a href="https://eodash.github.io/preview-instance/" target="_blank" rel="noreferrer">preview-instance</a> For checking your generated STAC catalog in a minimal eodash preview instance.</li></ul><h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This project will evolve iteratively, shaped by projects and community needs and interactions.</p><p>We welcome feedback and inputs through issues in respective components. If you are unsure where to create an issue, use the <a href="https://github.com/eodash/eodash/issues" target="_blank" rel="noreferrer">eodash issue board</a>.</p><p>Check <a href="https://github.com/orgs/eodash/projects/1" target="_blank" rel="noreferrer">our eodash project roadmap</a> to know about what are we planning next.</p>',11)])])}const u=a(n,[["render",s]]);export{g as __pageData,u as default};
